{"action":"tool_call","arguments":{"content":"import json
import sys
from pathlib import Path


SUCCESS = 0
USAGE_ERROR = 2
MISSING_FILE = 3
INVALID_INPUT = 4


def load_jsonl(path: Path) -> list[dict[str, str]]:
    """Load JSONL records.

    Each line must be a JSON object with string id and string status.
    Duplicate ids are invalid.
    Raise FileNotFoundError when the input path does not exist.
    Raise ValueError for malformed JSONL, invalid record schema, or duplicate ids.
    """
    records = []
    seen_ids = set()
    for raw_line in path.read_text().splitlines():
        if not raw_line.strip():
            continue
        try:
            record = json.loads(raw_line)
        except json.JSONDecodeError:
            raise ValueError("malformed JSON")

        if not isinstance(record, dict):
            raise ValueError("record is not a dictionary")

        if "id" not in record or "status" not in record:
            raise ValueError("missing id or status field")

        if not isinstance(record["id"], str) or not isinstance(record["status"], str):
            raise ValueError("id or status is not a string")

        if record["id"] in seen_ids:
            raise ValueError(f"duplicate id: {record["id"]}")

        seen_ids.add(record["id"])
        records.append(record)
    return records


def summarize_records(records: list[dict[str, str]]) -> dict[str, int]:
    """Return counts by status."""
    counts: dict[str, int] = {}
    for record in records:
        status = record["status"]
        counts[status] = counts.get(status, 0) + 1
    return counts


def main(argv: list[str] | None = None) -> int:
    """Run the CLI.

    Usage errors return 2, missing input files return 3, invalid input returns 4,
    and success returns 0. Expected user/input errors should not print tracebacks.
    """
    args = sys.argv[1:] if argv is None else argv
    if len(args) != 1:
        print("usage: python -m validate_records INPUT.jsonl", file=sys.stderr)
        return USAGE_ERROR

    try:
        records = load_jsonl(Path(args[0]))
        print(json.dumps(summarize_records(records)))
        return SUCCESS
    except FileNotFoundError:
        print(f"error: input file not found: {args[0]}", file=sys.stderr)
        return MISSING_FILE
    except ValueError as exc:
        print(f"error: {exc}", file=sys.stderr)
        return INVALID_INPUT
    except Exception as exc:
        print(f"error: {exc}", file=sys.stderr)
        return 1


if __name__ == "__main__":
    raise SystemExit(main())
